import { useState } from 'react'
import '../styles/skills.css'

/* ─── Skills ───────────────────────────────────────────────────────────────
   Features
   • Tab bar — Frontend / Backend / Tools
   • Skill cards with emoji icon, name, % label, animated fill bar
   • "Also familiar with" tag cloud at bottom
   ─────────────────────────────────────────────────────────────────────── */

const SKILLS = {
  Frontend: [
    { name: 'React.js',    level: 85, icon: '⚛️' },
    { name: 'JavaScript',  level: 80, icon: '🟨' },
    { name: 'HTML & CSS',  level: 92, icon: '🌐' },
    { name: 'TypeScript',  level: 60, icon: '🔷' },
  ],
  Backend: [
    { name: 'Node.js',     level: 75, icon: '🟩' },
    { name: 'Express.js',  level: 72, icon: '🚀' },
    { name: 'MongoDB',     level: 68, icon: '🍃' },
    { name: 'REST APIs',   level: 80, icon: '🔗' },
  ],
  Tools: [
    { name: 'Git & GitHub',level: 88, icon: '🐙' },
    { name: 'VS Code',     level: 95, icon: '💻' },
    { name: 'Postman',     level: 76, icon: '📮' },
    { name: 'Figma',       level: 55, icon: '🎨' },
  ],
}

const ALSO_KNOW = [
  'Python', 'MySQL', 'Firebase', 'Redux',
  'Bootstrap', 'Tailwind CSS', 'Linux', 'Docker basics',
]

/* ─────────────────────────────────────────────── */

const Skills = () => {
  const [active, setActive] = useState('Frontend')
  const tabs = Object.keys(SKILLS)

  return (
    <section id="skills" className="skills">
      <div className="container">

        <div className="section-header">
          <span className="section-tag">My Toolkit</span>
          <h2 className="section-title">Skills &amp; <span>Technologies</span></h2>
          <div className="divider" />
          <p className="section-subtitle">
            Technologies I use to build modern, full-stack web applications
          </p>
        </div>

        {/* ── Tab bar ── */}
        <div className="skills-tabs" role="tablist">
          {tabs.map(tab => (
            <button
              key={tab}
              role="tab"
              aria-selected={active === tab}
              className={`skills-tab ${active === tab ? 'active' : ''}`}
              onClick={() => setActive(tab)}
            >
              {tab}
            </button>
          ))}
        </div>

        {/* ── Skill cards ── */}
        <div className="skills-grid" role="tabpanel">
          {SKILLS[active].map(({ name, level, icon }) => (
            <div className="skill-card" key={name}>
              <div className="skill-header">
                <span className="skill-icon" aria-hidden="true">{icon}</span>
                <span className="skill-name">{name}</span>
                <span className="skill-pct">{level}%</span>
              </div>
              <div className="skill-bar" aria-label={`${name} proficiency`}>
                {/* CSS custom property drives the keyframe target */}
                <div
                  className="skill-bar-fill"
                  style={{ '--target-width': `${level}%` }}
                />
              </div>
            </div>
          ))}
        </div>

        {/* ── Tag cloud ── */}
        <div className="skills-also">
          <p className="skills-also-label">Also familiar with</p>
          <div className="skills-tags">
            {ALSO_KNOW.map(tech => (
              <span className="skills-tag" key={tech}>{tech}</span>
            ))}
          </div>
        </div>

      </div>
    </section>
  )
}

export default Skills
